    74→  Http::ResponseDecoder& decoder = *typedContext<HttpAttachContext>(context).decoder_;
    75→  Http::ConnectionPool::Callbacks& callbacks = *typedContext<HttpAttachContext>(context).callbacks_;
    76→  ENVOY_LOG(debug,
